class ModelTaskSpecPlacement(HomelabBaseModel):
    constraints: list[str] | None = Field(
        None,
        alias="Constraints",
        description="An array of constraint expressions to limit the set of nodes where\na task can be scheduled. Constraint expressions can either use a\n_match_ (`==`) or _exclude_ (`!=`) rule. Multiple constraints find\nnodes that satisfy every expression (AND match). Constraints can\nmatch node or Docker Engine labels as follows:\n\nnode attribute       | matches                        | example\n---------------------|--------------------------------|-----------------------------------------------\n`node.id`            | Node ID                        | `node.id==2ivku8v2gvtg4`\n`node.hostname`      | Node hostname                  | `node.hostname!=node-2`\n`node.role`          | Node role (`manager`/`worker`) | `node.role==manager`\n`node.platform.os`   | Node operating system          | `node.platform.os==windows`\n`node.platform.arch` | Node architecture              | `node.platform.arch==x86_64`\n`node.labels`        | User-defined node labels       | `node.labels.security==high`\n`engine.labels`      | Docker Engine's labels         | `engine.labels.operatingsystem==ubuntu-24.04`\n\n`engine.labels` apply to Docker Engine labels like operating system,\ndrivers, etc. Swarm administrators add `node.labels` for operational\npurposes by using the [`node update endpoint`](#operation/NodeUpdate).\n",
        examples=[
            [
                "node.hostname!=node3.corp.example.com",
                "node.role!=manager",
                "node.labels.type==production",
                "node.platform.os==linux",
                "node.platform.arch==x86_64",
            ]
        ],
    )
    preferences: list[ModelTaskSpecPlacementPreference] | None = Field(
        None,
        alias="Preferences",
        description="Preferences provide a way to make the scheduler aware of factors\nsuch as topology. They are provided in order from highest to\nlowest precedence.\n",
        examples=[
            [
                {"Spread": {"SpreadDescriptor": "node.labels.datacenter"}},
                {"Spread": {"SpreadDescriptor": "node.labels.rack"}},
            ]
        ],
    )
    max_replicas: int | None = Field(
        0,
        alias="MaxReplicas",
        description="Maximum number of replicas for per node (default value is 0, which\nis unlimited)\n",
    )
    platforms: list[Platform] | None = Field(
        None,
        alias="Platforms",
        description="Platforms stores all the platforms that the service's image can\nrun on. This field is used in the platform filter for scheduling.\nIf empty, then the platform filter is off, meaning there are no\nscheduling restrictions.\n",
    )


